'use client'

import { Suspense, useState, useEffect } from "react"
import { useParams, useRouter } from "next/navigation"
import MatchPlayer from "@/components/match/match-player"
import MatchInfo from "@/components/match/match-info" 
import { 
  ArrowLeft, 
  Minimize, 
  Share2, 
  Copy, 
  MessageSquare, 
  AlertTriangle, // 🔥 ADDED BACK
  CheckCircle,
  Twitter,
  Facebook,
  Tv,
  X,
  Clock
} from "lucide-react"
import "@/styles/match.css"
import { useLanguage } from "@/context/language-context"

// 🔥 RESPONSIVE CSS ENGINE
const pageStyles = `
  /* BASE RESET */
  .match-page-container {
    min-height: 100vh;
    width: 100%;
    background: #050505;
    padding-bottom: 40px;
    overflow-x: hidden;
  }

  /* TOP NAV */
  .top-nav {
    max-width: 1600px;
    margin: 0 auto;
    padding: 15px 20px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }
  .nav-back-wrapper {
    display: flex;
    align-items: center;
    gap: 15px;
    cursor: pointer;
    transition: opacity 0.2s;
  }

  /* GRID SYSTEM */
  .match-grid {
    display: grid;
    gap: 20px;
    max-width: 1600px;
    margin: 0 auto;
    padding: 20px;
    width: 100%;
    box-sizing: border-box;
  }
  
  /* LAYOUTS */
  .layout-standard { grid-template-columns: 1fr 340px; }
  .layout-cinema { grid-template-columns: 1fr; max-width: 1400px; }

  /* PLAYER */
  .player-wrapper {
    width: 100%;
    background: #000;
    aspect-ratio: 16/9;
    position: relative;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);
  }

  /* INFO BAR & CONTROLS */
  .info-bar {
    margin-top: 15px;
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    flex-wrap: wrap;
    gap: 15px;
    border-bottom: 1px solid #1a1a1a;
    padding-bottom: 15px;
  }
  .match-title-group {
    display: flex;
    flex-direction: column;
    gap: 8px;
  }
  .match-main-title {
    color: #fff;
    font-size: 20px;
    font-weight: 800;
    line-height: 1.2;
    font-family: sans-serif;
    margin: 0;
  }
  .meta-row {
    display: flex;
    align-items: center;
    gap: 10px;
  }
  .live-tag {
    background: #8db902;
    color: #000;
    font-size: 10px;
    font-weight: 900;
    padding: 2px 6px;
    border-radius: 3px;
    text-transform: uppercase;
  }
  .time-tag {
    color: #888;
    font-size: 12px;
    display: flex;
    align-items: center;
    gap: 4px;
    font-weight: 600;
  }

  /* CONTROLS (Desktop Default) */
  .controls-group {
    display: flex;
    gap: 10px;
    align-items: center;
  }

  /* CHAT PANEL */
  .chat-panel {
    background: #0a0a0a;
    border: 1px solid #1a1a1a;
    display: flex;
    flex-direction: column;
    height: 650px;
    overflow: hidden;
    border-radius: 8px;
  }

  /* 🔥 MOBILE OPTIMIZATIONS */
  @media (max-width: 1024px) {
    .match-grid {
      grid-template-columns: 100%;
      padding: 0;
      gap: 0;
    }
    .top-nav { padding: 10px 15px; }
    .nav-back-wrapper { gap: 10px; }
    .player-wrapper { width: 100vw; }
    
    .info-bar { 
      padding: 15px; 
      flex-direction: column; 
      gap: 15px; 
      align-items: stretch;
    }
    
    /* Force Controls into One Row on Mobile */
    .controls-group {
      justify-content: space-between;
      width: 100%;
    }
    
    /* Make buttons smaller on mobile */
    .action-btn {
      padding: 8px 10px !important;
      font-size: 10px !important;
    }
    
    .chat-panel {
      height: 500px;
      margin-top: 10px;
      border-radius: 0;
      border-left: none; 
      border-right: none;
    }
  }
`

function MatchPageContent() {
  const router = useRouter()
  const params = useParams()
  const matchId = String(params.id)
  const { t } = useLanguage()

  // --- STATES ---
  const [cinemaMode, setCinemaMode] = useState(false)
  const [chatAgreed, setChatAgreed] = useState(false)
  const [showEmbed, setShowEmbed] = useState(true) 
  const [copied, setCopied] = useState(false)
  
  // MATCH DATA
  const [matchTitle, setMatchTitle] = useState("Loading Stream...")
  const [startTime, setStartTime] = useState<string | null>(null)
  
  useEffect(() => {
    const stored = sessionStorage.getItem("currentMatch")
    if (stored) {
      try {
        const data = JSON.parse(stored)
        // Title Logic
        const displayTitle = data.title || data.competition || `${data.teams?.home?.name || 'Home'} vs ${data.teams?.away?.name || 'Away'}`
        setMatchTitle(displayTitle)
        
        // Time Logic
        if (data.date) {
            const dateObj = new Date(data.date)
            setStartTime(dateObj.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}))
        }
      } catch (e) {
        setMatchTitle("Live Stream")
      }
    }
  }, [])

  // SHARING
  const currentUrl = typeof window !== 'undefined' ? window.location.href : 'https://reedstreams.com'
  const shareText = `Watch ${matchTitle} Live on ReedStreams!`
  
  const shareLinks = {
    twitter: `https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText)}&url=${encodeURIComponent(currentUrl)}`,
    facebook: `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(currentUrl)}`,
    whatsapp: `https://wa.me/?text=${encodeURIComponent(shareText + " " + currentUrl)}`
  }

  const openShare = (url: string) => {
    window.open(url, '_blank', 'width=600,height=400')
  }

  const embedCode = `<iframe src="https://reedstreams.com/embed/${matchId}" width="100%" height="500" frameborder="0" allowfullscreen></iframe>`

  const handleCopy = () => {
    navigator.clipboard.writeText(embedCode)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  return (
    <>
      <style jsx global>{pageStyles}</style>
      
      <div className="match-page-container" style={{ background: cinemaMode ? '#000' : '#050505' }}>
        
        {/* 1. TOP NAV BAR */}
        {!cinemaMode && (
          <div className="top-nav">
            <div className="nav-back-wrapper" onClick={() => router.back()}>
              <div style={{
                width:'32px', height:'32px', background:'#1a1a1a', borderRadius:'50%', 
                display:'flex', alignItems:'center', justifyContent:'center', color:'#fff'
              }}>
                <ArrowLeft size={16} />
              </div>

              <div style={{fontSize:'20px', fontWeight:900, letterSpacing:'-1px', fontFamily:'sans-serif'}}>
                <span style={{color:'#fff'}}>REED</span>
                <span style={{color:'#8db902'}}>STREAMS</span>
              </div>
            </div>
            <div></div>
          </div>
        )}

        {/* 🔥 THE MAIN GRID */}
        <div className={`match-grid ${cinemaMode ? 'layout-cinema' : 'layout-standard'}`}>
          
          {/* === LEFT: PLAYER & INFO === */}
          <div className="player-section">
              
              {/* 🎥 THE VIDEO PLAYER */}
              <div className="player-wrapper">
                <MatchPlayer matchId={matchId} />
              </div>

              {/* 📊 INFO BAR (Title + Controls) */}
              <div className="info-bar">
                
                {/* LEFT: TITLE & TIME */}
                <div className="match-title-group">
                  <div className="meta-row">
                    <span className="live-tag">LIVE</span>
                    {startTime && (
                        <span className="time-tag">
                            <Clock size={12} /> Starts {startTime}
                        </span>
                    )}
                  </div>
                  <h1 className="match-main-title">{matchTitle}</h1>
                </div>

                {/* RIGHT: CONTROLS (One Row on Mobile) */}
                <div style={{display:'flex', flexDirection:'column', alignItems:'flex-end', gap:'10px', width: '100%'}}>
                   <div className="controls-group">
                      
                      {/* Cinema Toggle */}
                      <button 
                        className="action-btn"
                        onClick={() => setCinemaMode(!cinemaMode)}
                        style={{
                          background: '#111', border: '1px solid #222', color: cinemaMode ? '#8db902' : '#ccc',
                          padding: '8px 12px', borderRadius: '4px', fontSize: '11px', fontWeight: 700,
                          cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', textTransform: 'uppercase',
                          flex: 1, justifyContent: 'center'
                        }}
                      >
                        {cinemaMode ? <Minimize size={14}/> : <Tv size={14}/>}
                        {cinemaMode ? "Exit" : "Cinema"}
                      </button>

                      {/* Share Icons */}
                      {!cinemaMode && (
                         <div style={{display:'flex', gap:'6px', flex:1, justifyContent:'center'}}>
                            <button onClick={() => openShare(shareLinks.twitter)} style={{background:'#000', border:'1px solid #222', padding:'8px', borderRadius:'4px', cursor:'pointer'}}><Twitter size={16} color="#1DA1F2" /></button>
                            <button onClick={() => openShare(shareLinks.facebook)} style={{background:'#000', border:'1px solid #222', padding:'8px', borderRadius:'4px', cursor:'pointer'}}><Facebook size={16} color="#1877F2" /></button>
                            <button onClick={() => openShare(shareLinks.whatsapp)} style={{background:'#000', border:'1px solid #222', padding:'8px', borderRadius:'4px', cursor:'pointer'}}>
                              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="#25D366"><path d="M.057 24l1.687-6.163c-1.041-1.804-1.588-3.849-1.587-5.946.003-6.556 5.338-11.891 11.893-11.891 3.181.001 6.167 1.24 8.413 3.488 2.245 2.248 3.481 5.236 3.48 8.414-.003 6.557-5.338 11.892-11.893 11.892-1.99-.001-3.951-.5-5.688-1.448l-6.305 1.654zm6.597-3.807c1.676.995 3.276 1.591 5.392 1.592 5.448 0 9.886-4.434 9.889-9.885.002-5.462-4.415-9.89-9.881-9.892-5.452 0-9.887 4.434-9.889 9.884-.001 2.225.651 3.891 1.746 5.634l-.999 3.648 3.742-.981zm11.387-5.464c-.074-.124-.272-.198-.57-.347-.297-.149-1.758-.868-2.031-.967-.272-.099-.47-.149-.669.149-.198.297-.768.967-.941 1.165-.173.198-.347.223-.644.074-.297-.149-1.255-.462-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.297-.347.446-.521.151-.172.2-.296.3-.495.099-.198.05-.372-.025-.521-.075-.148-.669-1.611-.916-2.206-.242-.579-.487-.501-.669-.51l-.57-.01c-.198 0-.52.074-.792.372s-1.04 1.016-1.04 2.479 1.065 2.876 1.213 3.074c.149.198 2.095 3.2 5.076 4.487.709.306 1.263.489 1.694.626.712.226 1.36.194 1.872.118.571-.085 1.758-.719 2.006-1.413.248-.695.248-1.29.173-1.414z"/></svg>
                            </button>
                         </div>
                      )}
                      
                      {/* Embed Toggle */}
                      {!cinemaMode && (
                        <button 
                          className="action-btn"
                          onClick={() => setShowEmbed(!showEmbed)}
                          style={{
                            background: showEmbed ? '#222' : '#111', border: '1px solid #222', color: '#ccc',
                            padding: '8px 12px', borderRadius: '4px', fontSize: '11px', fontWeight: 700,
                            cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', textTransform: 'uppercase',
                            flex: 1, justifyContent: 'center'
                          }}
                        >
                          <Share2 size={14} /> Embed
                        </button>
                      )}
                   </div>

                   {/* 📜 EMBED CODE BOX (Placed nicely below controls) */}
                   {showEmbed && !cinemaMode && (
                      <div style={{width:'100%', animation:'fadeIn 0.3s'}}>
                        <div style={{
                          background:'#0a0a0a', padding:'10px', borderRadius:'6px', border:'1px solid #222', 
                          display:'flex', gap:'8px', alignItems:'center'
                        }}>
                          <input 
                            readOnly 
                            value={embedCode} 
                            style={{background:'transparent', border:'none', color:'#888', width:'100%', fontSize:'11px', fontFamily:'monospace', outline:'none'}} 
                          />
                          <button onClick={handleCopy} style={{background:'transparent', border:'none', cursor:'pointer', color: copied ? '#8db902' : '#fff'}}>
                            {copied ? <CheckCircle size={16} /> : <Copy size={16} />}
                          </button>
                          <button onClick={() => setShowEmbed(false)} style={{background:'transparent', border:'none', cursor:'pointer', color:'#444'}}>
                            <X size={14} />
                          </button>
                        </div>
                      </div>
                   )}
                </div>

              </div>
              
              {/* 📊 MATCH STATS (Hidden in Cinema) */}
              {!cinemaMode && (
                <div className="match-info-container">
                  <MatchInfo matchId={matchId} />
                </div>
              )}
          </div>

          {/* === RIGHT: CHAT SECTION === */}
          {!cinemaMode && (
            <div className="chat-panel">
                
                {/* CHAT HEADER */}
                <div style={{padding:'12px 15px', borderBottom:'1px solid #222', display:'flex', justifyContent:'space-between', alignItems:'center', background:'#0f0f0f'}}>
                    <span style={{color:'#fff', fontWeight:'bold', fontSize:'13px'}}>Live Chat</span>
                    <div style={{display:'flex', alignItems:'center', gap:'6px', fontSize:'11px', color:'#888'}}>
                      <div style={{width:'6px', height:'6px', background:'#8db902', borderRadius:'50%'}}></div> 
                      1.2k
                    </div>
                </div>
                
                {/* CHAT CONTENT */}
                <div style={{flex:1, position:'relative', background:'#050505'}}>
                  
                  {/* 🔒 "GOOD BOY" BLUR OVERLAY */}
                  {!chatAgreed && (
                    <div style={{
                      position:'absolute', top:0, left:0, width:'100%', height:'100%', 
                      background:'rgba(5,5,5,0.9)', backdropFilter:'blur(4px)', zIndex:10,
                      display:'flex', flexDirection:'column', justifyContent:'center', alignItems:'center', padding:'20px', textAlign:'center'
                    }}>
                      <AlertTriangle size={28} color="#8db902" style={{marginBottom:'10px'}} />
                      <h3 style={{color:'#fff', fontSize:'14px', fontWeight:'800', margin:'0 0 5px 0'}}>Chat Rules</h3>
                      <p style={{color:'#888', fontSize:'11px', lineHeight:'1.4', marginBottom:'15px', maxWidth:'180px'}}>
                        Be respectful. No hate speech. No spamming.
                      </p>
                      <button 
                        onClick={() => setChatAgreed(true)}
                        style={{
                          background:'#8db902', color:'#000', border:'none', padding:'8px 24px', 
                          borderRadius:'4px', fontSize:'11px', fontWeight:'800', cursor:'pointer',
                          textTransform:'uppercase'
                        }}
                      >
                        I Agree
                      </button>
                    </div>
                  )}

                  {/* 💬 PLACEHOLDER MESSAGES */}
                  <div className="chat-messages" style={{padding:'15px', height:'100%', overflowY:'auto'}}>
                    <div style={{color:'#444', fontSize:'11px', marginBottom:'10px', textAlign:'center', borderBottom:'1px solid #111', paddingBottom:'10px'}}>
                      Welcome to the chat room.
                    </div>
                    {[1,2,3,4,5].map((i) => (
                       <div key={i} style={{marginBottom:'8px', fontSize:'12px', display:'flex', gap:'8px'}}>
                         <span style={{color: i%2===0 ? '#8db902' : '#4a9eff', fontWeight:'bold', fontSize:'11px'}}>User{i*99}:</span>
                         <span style={{color:'#ccc'}}>This stream is fire! 🔥</span>
                       </div>
                    ))}
                  </div>

                </div>

                {/* INPUT AREA */}
                <div style={{padding:'12px', borderTop:'1px solid #222', background:'#0f0f0f'}}>
                    <input 
                      type="text" 
                      placeholder={chatAgreed ? "Type a message..." : "Agree to rules first"} 
                      disabled={!chatAgreed}
                      style={{
                        width:'100%', background:'#050505', border:'1px solid #222', 
                        padding:'10px 12px', borderRadius:'4px', color:'#fff', fontSize:'12px', outline:'none'
                      }} 
                    />
                </div>
            </div>
          )}

        </div>
      </div>
    </>
  )
}

export default function MatchPage() {
  return (
    <Suspense fallback={<div style={{color:'#444', textAlign:'center', marginTop:'50px'}}>Loading Arena...</div>}>
        <MatchPageContent />
    </Suspense>
  )
}